// ===== EDITA AQUESTES DUES URLS =====
const SIM_URL = "http://localhost:8000";   // domini públic de Railway en prod
const SHEET_URL = "https://script.google.com/macros/s/XXXX/exec";

flow.set("SHEET_URL", SHEET_URL);

const scenarios = [
  { id: "base",      params: { num_buses: 2, num_stops: 3, capacity: 100000, variable_demand: false, sim_time: 480, seed: 42 } },
  { id: "finite",    params: { num_buses: 2, num_stops: 3, capacity: 50,     variable_demand: false, sim_time: 480, seed: 42 } },
  { id: "variable",  params: { num_buses: 2, num_stops: 3, capacity: 50,     variable_demand: true,  sim_time: 480, seed: 42 } },
  { id: "realistic", params: { num_buses: 4, num_stops: 6, capacity: 50,     variable_demand: true,  sim_time: 480, seed: 42 } }
];

scenarios.forEach(function (s) {
  node.send({
    url: SIM_URL + "/simulate",
    method: "POST",
    headers: { "Content-Type": "application/json" },
    payload: s.params,
    scenario: s.id,
    simParams: s.params
  });
});
return null;

function qs(o) {
  return Object.keys(o).map(function (k) {
    return encodeURIComponent(k) + "=" + encodeURIComponent(o[k]);
  }).join("&");
}

const m = msg.payload.metrics;
const p = msg.simParams;

const data = {
  op: "append",
  num_buses: p.num_buses, num_stops: p.num_stops, capacity: p.capacity,
  sim_time: p.sim_time, variable_demand: p.variable_demand, seed: p.seed,
  mean_wait: m.mean_wait, mean_headway: m.mean_headway, headway_cv: m.headway_cv,
  total_rejected: m.total_rejected, max_queue: m.max_queue, mean_occupancy: m.mean_occupancy
};

msg.url = flow.get("SHEET_URL") + "?" + qs(data);
msg.method = "GET";
msg.headers = {};
msg.payload = "";
node.status({ fill: "blue", shape: "dot", text: msg.scenario + " cv=" + m.headway_cv });
return msg;
